queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?journalists a :Journalists .
    ?journalists p:name ?name .
    ?journalists p:languages ?languages_f .
    FILTER(STR(?languages_f) = "English and Spanish")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?editors a :Editors .
    ?editors p:name ?name .
    ?editors p:languages ?languages_f .
    FILTER(STR(?languages_f) = "English and Spanish")
    BIND(?name AS ?o0)
  }
}

